function convertHtmlToMd(e){let t=toMarkdown(e,{converters:[{filter:"div",replacement:function(e){return e}}]});return t}function getRawHTML(e,t){let n=`<!DOCTYPE html>
    <html>
    <head>
      <meta charset='utf-8'>
      <meta name='viewport' content='width=device-width'>
      <title>`+t+`</title>
      <style> body { font-family: 'Helvetica Neue', Helvetica, Arial, sans-serif; padding:1em; } </style>
    </head>
    <body>
    `+e+`
    </body>
    </html>
      `;return n}window.getContent=function(e){const t=document.getElementById(e);return t?t.innerHTML:""};function getTitle(e){var t=document.getElementById(e),n=t.getElementsByTagName("strong")[0];return n.innerHTML}function loadInTextView(e,t){document.getElementById(e).value=t}